#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use HTML::Entities;
use HTML::Scrubber;

my $cgi = CGI->new;

my $comment = $cgi->param('comment') || '';

my $scrubber = HTML::Scrubber->new(
    allow => [qw[ p br b i u em strong a ]],
    rules => [
        a => {
            href => qr{^(?:https?://|/)}i,
            title => 1,
            target => qr{^_blank$}i,
        },
    ],
    default => [0, { '*' => 0 }],
);

$scrubber->comment(0);
$scrubber->process(0);

my $sanitized_comment = $scrubber->scrub($comment);

print $cgi->header('text/html; charset=UTF-8');
print "<div>$sanitized_comment</div>";